/**
 * Logic for the Backend requirement: SEO Image Renaming
 * Pattern: san-juan-inmobiliaria-[indice]-[timestamp].jpg
 */
export const renameImageForSEO = (index: number, originalName: string): string => {
  const timestamp = Date.now();
  const extension = originalName.split('.').pop() || 'jpg';
  return `san-juan-inmobiliaria-${index}-${timestamp}.${extension}`;
};

export const generateAltText = (propertyTitle: string, index: number): string => {
  return `${propertyTitle} - San Juan Inmobiliaria - Vista ${index + 1}`;
};

import { Property, SyncStats } from '../types';

/**
 * Mocks the backend Cron Job / Service logic for CRM Gvamax.
 */
export const syncWithGvamax = async (): Promise<SyncStats> => {
  // Simulating API latency
  await new Promise(resolve => setTimeout(resolve, 2000));

  console.log("Fetching from Gvamax API...");
  // In a real scenario: fetch('https://api.gvamax.com.ar/v1/properties')

  return {
    lastSync: new Date().toISOString(),
    totalSynced: Math.floor(Math.random() * 50) + 10,
    errors: []
  };
};

/**
 * Extract coordinates from a Google Maps URL
 */
export const extractCoordsFromUrl = (url: string): { lat: number; lng: number } | null => {
  const regex = /@(-?\d+\.\d+),(-?\d+\.\d+)/;
  const match = url.match(regex);
  if (match) {
    return {
      lat: parseFloat(match[1]),
      lng: parseFloat(match[2])
    };
  }
  return null;
};

