import React, { useState } from 'react';
import { Property } from '../types';
import { MOCK_PROPERTIES } from '../constants';
import { syncWithGvamax } from '../services/syncService';

const AdminDashboard: React.FC = () => {
  const [properties, setProperties] = useState<Property[]>(MOCK_PROPERTIES);
  const [isSyncing, setIsSyncing] = useState(false);
  const [lastSyncResult, setLastSyncResult] = useState<string | null>(null);

  const handleSync = async () => {
    setIsSyncing(true);
    try {
      const stats = await syncWithGvamax();
      setLastSyncResult(`Sincronización exitosa: ${stats.totalSynced} propiedades actualizadas.`);
    } catch (e) {
      setLastSyncResult("Error en la sincronización.");
    } finally {
      setIsSyncing(false);
    }
  };

  const handleDuplicate = (id: string) => {
    const property = properties.find(p => p.id === id);
    if (property) {
      const duplicated = {
        ...property,
        id: Math.random().toString(36).substring(7),
        ref: `${property.ref}-COPY`,
        title: `${property.title} (Copia)`,
        createdAt: new Date().toISOString()
      };
      setProperties([duplicated, ...properties]);
      alert("Propiedad duplicada con éxito.");
    }
  };

  const handleDelete = (id: string) => {
    if (confirm("¿Seguro que desea archivar esta propiedad?")) {
      setProperties(properties.map(p => p.id === id ? { ...p, status: 'archived' as const } : p));
    }
  };

  return (
    <div className="max-w-7xl mx-auto p-4 md:p-8">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
        <div>
          <h1 className="text-3xl font-bold text-slate-900">CMS Bermudez-Moya</h1>
          <p className="text-slate-500">Gestión de propiedades y sincronización CRM Gvamax</p>
        </div>

        <button 
          onClick={handleSync}
          disabled={isSyncing}
          className={`flex items-center gap-2 px-6 py-3 rounded-lg font-bold transition-all ${
            isSyncing ? 'bg-slate-200 text-slate-400' : 'bg-blue-600 hover:bg-blue-700 text-white shadow-lg'
          }`}
        >
          {isSyncing ? (
            <svg className="animate-spin h-5 w-5 mr-3" viewBox="0 0 24 24">
              <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
              <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
            </svg>
          ) : (
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
            </svg>
          )}
          {isSyncing ? 'Sincronizando...' : 'Sincronizar con Gvamax'}
        </button>
      </div>

      {lastSyncResult && (
        <div className="bg-blue-50 border-l-4 border-blue-600 p-4 mb-8 text-blue-800 rounded-r-lg">
          {lastSyncResult}
        </div>
      )}

      {/* Properties List */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <table className="min-w-full divide-y divide-slate-200">
          <thead className="bg-slate-50">
            <tr>
              <th className="px-6 py-4 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">Propiedad</th>
              <th className="px-6 py-4 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">Ref / Tipo</th>
              <th className="px-6 py-4 text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">Estado</th>
              <th className="px-6 py-4 text-right text-xs font-semibold text-slate-500 uppercase tracking-wider">Acciones</th>
            </tr>
          </thead>
          <tbody className="bg-white divide-y divide-slate-200">
            {properties.map((p) => (
              <tr key={p.id} className="hover:bg-slate-50 transition-colors">
                <td className="px-6 py-4 whitespace-nowrap">
                  <div className="flex items-center">
                    <img className="h-12 w-16 rounded object-cover mr-4" src={p.images[0]?.url} alt="" />
                    <div className="text-sm font-bold text-slate-900">{p.title}</div>
                  </div>
                </td>
                <td className="px-6 py-4 whitespace-nowrap">
                  <div className="text-xs font-mono text-slate-500 mb-1">{p.ref}</div>
                  <div className="text-sm text-slate-900">{p.type} en {p.operation}</div>
                </td>
                <td className="px-6 py-4 whitespace-nowrap">
                  <span className={`px-3 py-1 text-xs font-bold rounded-full uppercase ${
                    p.status === 'active' ? 'bg-green-100 text-green-700' : 'bg-slate-100 text-slate-500'
                  }`}>
                    {p.status}
                  </span>
                </td>
                <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                  <button onClick={() => handleDuplicate(p.id)} className="text-blue-600 hover:text-blue-900 mr-4 font-bold">Duplicar</button>
                  <button className="text-slate-600 hover:text-slate-900 mr-4 font-bold">PDF</button>
                  <button onClick={() => handleDelete(p.id)} className="text-red-600 hover:text-red-900 font-bold">Archivar</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default AdminDashboard;

