            <div className="lg:hidden fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 p-4 z-[100] flex gap-3 shadow-[0_-10px_30px_rgba(0,0,0,0.05)]">
               <WhatsAppButton propertyRef={selectedProperty.ref} propertyTitle={selectedProperty.title} />
            </div>
          </div>
        </div>
      );
    }

    return (
      <div className="max-w-7xl mx-auto px-4 md:px-8 py-12">
        <header className="mb-16 text-center">
          <h1 className="text-7xl font-black text-slate-900 mb-6 tracking-tighter leading-none">
            Encuentra tu lugar <br/><span className="text-blue-600">Bermudez-Moya</span>
          </h1>
          <p className="text-xl text-slate-500 max-w-2xl mx-auto font-light leading-relaxed">
            Explora propiedades exclusivas sincronizadas en tiempo real con nuestro CRM.
