            <h4 className="text-white font-black uppercase tracking-widest text-xs mb-8">Servicios</h4>
            <ul className="space-y-4 text-sm font-medium">
              <li className="hover:text-white cursor-pointer transition-colors" onClick={() => setView('services')}>Gestión Inmobiliaria</li>
              <li className="hover:text-white cursor-pointer transition-colors" onClick={() => setView('services')}>Tasaciones</li>
