export default App;

export enum PropertyType {
  HOUSE = 'Casa',
  APARTMENT = 'Departamento',
  LOT = 'Lote',
  OFFICE = 'Oficina',
  COMMERCIAL = 'Local'
}

export enum OperationType {
  SALE = 'Venta',
  RENT = 'Alquiler',
  TEMPORARY = 'Alquiler Temporario'
}

export interface PropertyImage {
  id: string;
  url: string;
  fileName: string;
  altText: string;
  order: number;
}

export interface Property {
  id: string;
  externalId: string; // ID de Gvamax
  ref: string;
  title: string;
  description: string;
  type: PropertyType;
  operation: OperationType;
  price: number;
  currency: 'USD' | 'ARS';
  neighborhood: string;
  location: {
    address: string;
    city: string;
    lat?: number;
    lng?: number;
    googleMapsUrl?: string;
  };
  features: {
    rooms: number;
    bedrooms: number;
    bathrooms: number;
    m2Total: number;
    m2Covered: number;
    amenities: string[];
  };
  images: PropertyImage[];
  status: 'active' | 'sold' | 'rented' | 'archived';
  viewsCount: number;
  leadsCount: number;
  createdAt: string;
  updatedAt: string;
  lastSyncAt: string;
}

export interface Lead {
  id: string;
  name: string;
  email: string;
  phone: string;
  message: string;
  propertyId?: string;
  propertyRef?: string;
  status: 'new' | 'contacted' | 'closed' | 'discarded';
  createdAt: string;
  source: 'whatsapp' | 'web_form' | 'direct';
}

export interface SyncStats {
  lastSync: string;
  totalSynced: number;
  added: number;
  updated: number;
  deleted: number;
  errors: string[];
}

import React, { useState, useMemo } from 'react';
import { Property, PropertyType, OperationType, SyncStats, Lead } from '../types';
import { MOCK_PROPERTIES, MOCK_LEADS } from '../constants';
import { syncWithGvamax, extractCoordsFromUrl } from '../services/syncService';
import { renameImageForSEO, generateAltText } from '../services/imageService';

type AdminView = 'overview' | 'properties' | 'leads' | 'sync' | 'settings';

const AdminDashboard: React.FC = () => {
  const [activeView, setActiveView] = useState<AdminView>('overview');
  const [properties, setProperties] = useState<Property[]>(MOCK_PROPERTIES);
  const [leads, setLeads] = useState<Lead[]>(MOCK_LEADS);
  const [isSyncing, setIsSyncing] = useState(false);
  const [syncHistory, setSyncHistory] = useState<SyncStats[]>([]);
  const [editingProperty, setEditingProperty] = useState<Property | null>(null);
  const [selectedLead, setSelectedLead] = useState<Lead | null>(null);

  // Statistics Calculation
  const stats = useMemo(() => {
    return {
      total: properties.length,
      active: properties.filter(p => p.status === 'active').length,
      leads: leads.length,
      newLeads: leads.filter(l => l.status === 'new').length,
      views: properties.reduce((acc, p) => acc + p.viewsCount, 0),
    };
  }, [properties, leads]);

  const handleSync = async () => {
    setIsSyncing(true);
    try {
      const result = await syncWithGvamax();
      setSyncHistory([result, ...syncHistory]);
      alert(`Sincronización finalizada. +${result.added} nuevas, ${result.updated} actualizadas.`);
    } catch (e) {
      alert("Error en la sincronización.");
    } finally {
      setIsSyncing(false);
    }
  };

  const updateLeadStatus = (leadId: string, newStatus: Lead['status']) => {
    setLeads(leads.map(l => l.id === leadId ? { ...l, status: newStatus } : l));
  };

  const handleDuplicate = (id: string) => {
    const property = properties.find(p => p.id === id);
    if (property) {
      const duplicated = {
        ...property,
        id: Math.random().toString(36).substring(7),
        ref: `${property.ref}-CLONE-${Math.floor(Math.random() * 1000)}`,
        title: `${property.title} (COPIA)`,
        createdAt: new Date().toISOString(),
        viewsCount: 0,
        leadsCount: 0
      };
      setProperties([duplicated, ...properties]);
    }
  };

  const handleArchive = (id: string) => {
    if (confirm("¿Seguro que desea archivar esta propiedad? Dejará de ser visible en el sitio público.")) {
      setProperties(properties.map(p => p.id === id ? { ...p, status: 'archived' as const } : p));
    }
  };

  const handleSaveProperty = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingProperty) {
      setProperties(properties.map(p => p.id === editingProperty.id ? editingProperty : p));
      setEditingProperty(null);
    }
  };

  const handleAutoRename = (propertyId: string) => {
    const property = properties.find(p => p.id === propertyId);
    if (!property) return;

    const updatedImages = property.images.map((img, idx) => ({
      ...img,
      fileName: renameImageForSEO(property, idx),
      altText: generateAltText(property, idx)
    }));

    setProperties(properties.map(p => p.id === propertyId ? { ...p, images: updatedImages } : p));
    alert("Imágenes renombradas físicamente para SEO y Alt-Text actualizado.");
  };

  return (
    <div className="flex min-h-[calc(100vh-6rem)] bg-slate-50">
      {/* Sidebar Navigation */}
      <aside className="w-64 bg-white border-r border-slate-200 p-6 space-y-2 hidden md:block">
        <button 
          onClick={() => setActiveView('overview')}
          className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-bold transition-all ${activeView === 'overview' ? 'bg-blue-50 text-blue-600' : 'text-slate-500 hover:bg-slate-50'}`}
        >
