                    </div>
                 </div>

                 <div className="space-y-2">
                    <h4 className="text-xs font-black text-slate-400 uppercase tracking-widest">Mensaje / Consulta</h4>
                    <div className="bg-blue-50 p-6 rounded-3xl text-slate-700 font-medium leading-relaxed italic">
                      "{selectedLead.message}"
                    </div>
                 </div>

                 {selectedLead.propertyRef && (
                   <div className="p-4 bg-slate-900 rounded-2xl flex items-center justify-between">
                      <div className="flex items-center gap-3">
                         <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center">
                            <svg className="w-4 h-4 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6" /></svg>
                         </div>
                         <span className="text-white text-xs font-bold">Interesado en {selectedLead.propertyRef}</span>
                      </div>
                      <button className="text-blue-400 text-[10px] font-black uppercase hover:text-blue-300">Ver Publicación</button>
                   </div>
                 )}
              </div>

              <footer className="p-8 pt-0 flex gap-4">
                 <button 
                  onClick={() => {
                    const waMsg = encodeURIComponent(`Hola ${selectedLead.name}, te contacto de Bermudez-Moya Group por tu consulta...`);
                    window.open(`https://wa.me/${selectedLead.phone.replace(/[^0-9]/g, '')}?text=${waMsg}`, '_blank');
                    updateLeadStatus(selectedLead.id, 'contacted');
                  }}
                  className="flex-1 bg-green-500 text-white font-black py-4 rounded-2xl uppercase tracking-widest text-xs hover:bg-green-600 shadow-xl shadow-green-100 transition-all flex items-center justify-center gap-2"
                 >
                    <svg className="w-5 h-5 fill-current" viewBox="0 0 24 24"><path d="M12.031 6.172c-3.181 0-5.767 2.586-5.768 5.766-.001 1.298.38 2.27 1.019 3.287l-.582 2.128 2.182-.573c.978.58 1.911.928 3.145.929 3.178 0 5.767-2.587 5.768-5.766.001-3.187-2.575-5.771-5.764-5.771zm3.392 8.244c-.144.405-.837.774-1.17.824-.299.045-.677.063-1.092-.069-.252-.08-.575-.187-.988-.365-1.739-.747-2.874-2.512-2.96-2.626-.088-.113-.716-.953-.716-1.819 0-.866.454-1.292.614-1.457.16-.165.346-.207.461-.207.115 0 .23 0 .331.005.106.005.25-.039.391.305.143.349.491 1.196.535 1.283.043.088.072.19.014.305-.058.115-.088.19-.174.29-.088.098-.184.221-.264.295-.088.081-.18.17-.078.347.103.177.459.755.984 1.222.674.6 1.242.787 1.419.874.177.088.28.073.385-.048.103-.121.442-.512.561-.686.118-.174.237-.145.399-.086.163.058 1.026.484 1.203.573.177.089.294.133.336.207.042.073.042.427-.101.831z"/></svg>
                    WhatsApp
                 </button>
                 <button 
                  onClick={() => updateLeadStatus(selectedLead.id, 'discarded')}
                  className="px-6 py-4 border-2 border-slate-100 text-slate-400 font-bold rounded-2xl hover:bg-red-50 hover:text-red-500 hover:border-red-100 transition-all uppercase text-[10px] tracking-widest"
                 >
                    Descartar
                 </button>
              </footer>
           </div>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;

export enum PropertyType {
  HOUSE = 'Casa',
  APARTMENT = 'Departamento',
  LOT = 'Lote',
  OFFICE = 'Oficina',
  COMMERCIAL = 'Local'
}

export enum OperationType {
  SALE = 'Venta',
  RENT = 'Alquiler',
  TEMPORARY = 'Alquiler Temporario'
}

export interface PropertyImage {
  id: string;
  url: string;
  fileName: string;
  altText: string;
  order: number;
}

export interface Property {
  id: string;
  externalId: string; // ID de Gvamax
  ref: string;
  title: string;
  description: string;
  type: PropertyType;
  operation: OperationType;
  price: number;
  currency: 'USD' | 'ARS';
  neighborhood: string;
  location: {
    address: string;
    city: string;
    province: string;
    department: string;
    locality: string;
    lat?: number;
    lng?: number;
    googleMapsUrl?: string;
  };
  features: {
    rooms: number;
    bedrooms: number;
    bathrooms: number;
    m2Total: number;
    m2Covered: number;
    amenities: string[];
  };
  images: PropertyImage[];
  status: 'active' | 'sold' | 'rented' | 'archived';
  viewsCount: number;
  leadsCount: number;
  createdAt: string;
  updatedAt: string;
  lastSyncAt: string;
}

export interface Lead {
  id: string;
  name: string;
  email: string;
  phone: string;
  message: string;
  propertyId?: string;
  propertyRef?: string;
  status: 'new' | 'contacted' | 'closed' | 'discarded';
  createdAt: string;
  source: 'whatsapp' | 'web_form' | 'direct';
}

export interface SyncStats {
  lastSync: string;
  totalSynced: number;
  added: number;
  updated: number;
  deleted: number;
  errors: string[];
}

import React, { useState, useMemo } from 'react';
import { Property, PropertyType, OperationType } from './types';
import { MOCK_PROPERTIES } from './constants';
import PropertyCard from './components/PropertyCard';
import WhatsAppButton from './components/WhatsAppButton';
import AdminDashboard from './components/AdminDashboard';
import StickyContactSidebar from './components/StickyContactSidebar';
import ServicesSection from './components/ServicesSection';
import ContactSection from './components/ContactSection';
import AboutUsSection from './components/AboutUsSection';

type ViewType = 'home' | 'services' | 'admin' | 'nosotros' | 'contacto';
type SortOption = 'newest' | 'oldest' | 'price-asc' | 'price-desc';

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('home');
  const [selectedPropertyId, setSelectedPropertyId] = useState<string | null>(null);

  const [search, setSearch] = useState('');
  const [typeFilter, setTypeFilter] = useState<PropertyType | 'All'>('All');
  const [opFilter, setOpFilter] = useState<OperationType | 'All'>('All');
  const [provinceFilter, setProvinceFilter] = useState<string>('All');
  const [departmentFilter, setDepartmentFilter] = useState<string>('All');
  const [localityFilter, setLocalityFilter] = useState<string>('All');
  const [selectedAmenities, setSelectedAmenities] = useState<string[]>([]);
  const [sortBy, setSortBy] = useState<SortOption>('newest');

  // Derivar opciones únicas de ubicación de las propiedades disponibles
  const locationOptions = useMemo(() => {
    const provinces = new Set<string>();
    const departments = new Set<string>();
    const localities = new Set<string>();

    MOCK_PROPERTIES.forEach(p => {
      if (p.location.province) provinces.add(p.location.province);

      // Filtrar departamentos basados en provincia seleccionada
      if (provinceFilter === 'All' || p.location.province === provinceFilter) {
        if (p.location.department) departments.add(p.location.department);
      }

      // Filtrar localidades basadas en provincia y departamento seleccionados
      const matchesProv = provinceFilter === 'All' || p.location.province === provinceFilter;
      const matchesDept = departmentFilter === 'All' || p.location.department === departmentFilter;
      if (matchesProv && matchesDept) {
        if (p.location.locality) localities.add(p.location.locality);
      }
    });

    return {
      provinces: Array.from(provinces).sort(),
      departments: Array.from(departments).sort(),
      localities: Array.from(localities).sort()
    };
  }, [provinceFilter, departmentFilter]);

  const allAmenities = useMemo(() => {
    const amenities = new Set<string>();
    MOCK_PROPERTIES.forEach(p => p.features.amenities.forEach(a => amenities.add(a)));
    return Array.from(amenities).sort();
  }, []);

  const filteredAndSortedProperties = useMemo(() => {
    let result = MOCK_PROPERTIES.filter(p => {
      const matchesSearch = p.title.toLowerCase().includes(search.toLowerCase()) || 
                           p.neighborhood?.toLowerCase().includes(search.toLowerCase()) ||
                           p.location.address.toLowerCase().includes(search.toLowerCase());
      const matchesType = typeFilter === 'All' || p.type === typeFilter;
      const matchesOp = opFilter === 'All' || p.operation === opFilter;

      // Filtros de ubicación
      const matchesProv = provinceFilter === 'All' || p.location.province === provinceFilter;
      const matchesDept = departmentFilter === 'All' || p.location.department === departmentFilter;
      const matchesLoc = localityFilter === 'All' || p.location.locality === localityFilter;

      const matchesAmenities = selectedAmenities.length === 0 || 
                               selectedAmenities.every(a => p.features.amenities.includes(a));

      return matchesSearch && matchesType && matchesOp && matchesProv && matchesDept && matchesLoc && matchesAmenities && p.status === 'active';
    });

    return result.sort((a, b) => {
      switch (sortBy) {
        case 'price-asc': return a.price - b.price;
        case 'price-desc': return b.price - a.price;
        case 'oldest': return new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime();
        case 'newest':
        default: return new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime();
      }
    });
  }, [search, typeFilter, opFilter, provinceFilter, departmentFilter, localityFilter, selectedAmenities, sortBy]);

  const selectedProperty = useMemo(() => 
    MOCK_PROPERTIES.find(p => p.id === selectedPropertyId)
  , [selectedPropertyId]);

  const renderHome = () => {
    if (selectedProperty) {
      return (
        <div className="max-w-7xl mx-auto p-4 md:p-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <button 
            onClick={() => setSelectedPropertyId(null)}
            className="group flex items-center gap-2 text-blue-600 font-bold mb-8 hover:text-blue-800 transition-colors"
          >
            <svg className="w-5 h-5 transition-transform group-hover:-translate-x-1" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 19l-7-7m0 0l7-7m-7 7h18" />
            </svg>
            Volver al buscador de propiedades
          </button>

          <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">
            {/* Main Content */}
            <div className="lg:col-span-2 space-y-12">
              <div className="space-y-4">
                <div className="rounded-3xl overflow-hidden shadow-2xl aspect-[16/9] bg-slate-100">
                  <img src={selectedProperty.images[0]?.url} alt={selectedProperty.images[0]?.altText} className="w-full h-full object-cover" />
                </div>
                <div className="grid grid-cols-4 gap-4">
                  {selectedProperty.images.slice(1, 5).map(img => (
                    <div key={img.id} className="rounded-2xl overflow-hidden shadow-sm aspect-[4/3] bg-slate-100">
                      <img src={img.url} alt={img.altText} className="w-full h-full object-cover hover:scale-110 transition-transform cursor-pointer" />
                    </div>
                  ))}
                </div>
              </div>

              <div>
                <div className="flex flex-wrap gap-2 mb-6">
                  <span className="bg-blue-600 text-white px-4 py-1.5 rounded-full text-xs font-black uppercase tracking-widest">{selectedProperty.operation}</span>
                  <span className="bg-slate-900 text-white px-4 py-1.5 rounded-full text-xs font-black uppercase tracking-widest">{selectedProperty.type}</span>
                </div>
                <h1 className="text-5xl font-black text-slate-900 mb-4 tracking-tight leading-tight">{selectedProperty.title}</h1>
                <p className="text-2xl text-slate-500 flex items-center gap-3 font-light">
                   <svg className="w-6 h-6 text-blue-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" />
                  </svg>
                  {selectedProperty.location.address}, {selectedProperty.neighborhood || 'Barrio'}
                </p>
              </div>

              <div className="grid grid-cols-2 md:grid-cols-4 gap-4 p-8 bg-slate-50 rounded-3xl border border-slate-100">
                <div className="text-center md:border-r border-slate-200">
                  <p className="text-slate-400 text-[10px] font-black uppercase mb-1 tracking-widest">Dormitorios</p>
                  <p className="text-3xl font-black text-slate-900">{selectedProperty.features.rooms}</p>
                </div>
                <div className="text-center md:border-r border-slate-200">
                  <p className="text-slate-400 text-[10px] font-black uppercase mb-1 tracking-widest">Baños</p>
                  <p className="text-3xl font-black text-slate-900">{selectedProperty.features.bathrooms}</p>
                </div>
                <div className="text-center md:border-r border-slate-200">
                  <p className="text-slate-400 text-[10px] font-black uppercase mb-1 tracking-widest">Cubiertos</p>
                  <p className="text-3xl font-black text-slate-900">{selectedProperty.features.m2Covered} m²</p>
                </div>
                <div className="text-center">
                  <p className="text-slate-400 text-[10px] font-black uppercase mb-1 tracking-widest">Totales</p>
                  <p className="text-3xl font-black text-slate-900">{selectedProperty.features.m2Total} m²</p>
                </div>
              </div>

              <div className="prose prose-slate max-w-none">
                <h3 className="text-2xl font-black text-slate-900 mb-6">Descripción de la Propiedad</h3>
                <p className="text-slate-600 text-lg leading-relaxed whitespace-pre-line">
                  {selectedProperty.description}
                </p>
              </div>

              {selectedProperty.features.amenities.length > 0 && (
                <div className="pt-8 border-t border-slate-100">
                  <h3 className="text-2xl font-black text-slate-900 mb-6">Comodidades y Amenities</h3>
                  <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
                    {selectedProperty.features.amenities.map(a => (
                      <div key={a} className="flex items-center gap-3 text-slate-700 bg-white p-4 rounded-2xl border border-slate-100 shadow-sm">
                        <div className="w-2 h-2 rounded-full bg-blue-500"></div>
                        <span className="font-semibold text-sm">{a}</span>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>

            <div className="hidden lg:block relative">
              <StickyContactSidebar property={selectedProperty} />
            </div>

            <div className="lg:hidden fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 p-4 z-[100] flex gap-3 shadow-[0_-10px_30px_rgba(0,0,0,0.05)]">
               <WhatsAppButton propertyRef={selectedProperty.ref} propertyTitle={selectedProperty.title} />
            </div>
          </div>
        </div>
      );
    }

    return (
      <div className="max-w-7xl mx-auto px-4 md:px-8 py-12">
        <header className="mb-12 text-center">
          <h1 className="text-7xl font-black text-slate-900 mb-6 tracking-tighter leading-none">
            Encuentra tu lugar <br/><span className="text-blue-600">Bermudez-Moya</span>
          </h1>
          <p className="text-xl text-slate-500 max-w-2xl mx-auto font-light leading-relaxed">
            Explora propiedades exclusivas sincronizadas en tiempo real con nuestro CRM.
          </p>
        </header>

        <div className="space-y-4 mb-16">
          {/* Main Search Bar Card */}
          <div className="bg-white p-4 md:p-6 rounded-[3rem] shadow-2xl shadow-blue-900/5 border border-slate-100">
            <div className="flex flex-col gap-4">
              {/* Row 1: Search and Main Filters */}
              <div className="flex flex-col lg:flex-row gap-3 items-center w-full">
                <div className="flex-[4] relative w-full">
                  <svg className="w-5 h-5 absolute left-6 top-1/2 -translate-y-1/2 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                  </svg>
                  <input 
                    type="text" 
                    placeholder="Busca por barrio, calle o referencia..."
                    className="w-full pl-14 pr-6 py-5 bg-slate-50 border border-blue-50 rounded-[2rem] focus:ring-4 focus:ring-blue-500/10 transition-all outline-none text-slate-700 font-medium"
                    value={search}
                    onChange={(e) => setSearch(e.target.value)}
                  />
                </div>

                <div className="flex flex-1 gap-2 w-full lg:w-auto">
                  <select 
                    className="flex-1 px-6 py-5 bg-slate-50 border-none rounded-[2rem] focus:ring-4 focus:ring-blue-500/10 outline-none font-bold text-slate-600 text-sm appearance-none text-center"
                    value={typeFilter}
                    onChange={(e) => setTypeFilter(e.target.value as any)}
                  >
                    <option value="All">Tipos</option>
                    {Object.values(PropertyType).map(t => <option key={t} value={t}>{t}</option>)}
                  </select>
                  <select 
                    className="flex-1 px-6 py-5 bg-slate-50 border-none rounded-[2rem] focus:ring-4 focus:ring-blue-500/10 outline-none font-bold text-slate-600 text-sm appearance-none text-center"
                    value={opFilter}
                    onChange={(e) => setOpFilter(e.target.value as any)}
                  >
                    <option value="All">Operación</option>
                    {Object.values(OperationType).map(o => <option key={o} value={o}>{o}</option>)}
                  </select>
                </div>

                <div className="w-full lg:w-48">
                  <select 
                    className="w-full px-6 py-5 bg-blue-600 text-white border-none rounded-[2rem] focus:ring-4 focus:ring-blue-500/10 outline-none font-bold text-sm text-center appearance-none"
                    value={sortBy}
                    onChange={(e) => setSortBy(e.target.value as SortOption)}
                  >
                    <option value="newest">Más recientes</option>
                    <option value="price-asc">Menor Precio</option>
                    <option value="price-desc">Mayor Precio</option>
                  </select>
                </div>
              </div>

              {/* Row 2: Location Selects */}
              <div className="grid grid-cols-1 md:grid-cols-3 gap-3 w-full">
                <select 
                  className="px-6 py-4 bg-slate-50 border-none rounded-[2rem] focus:ring-4 focus:ring-blue-500/10 outline-none font-bold text-slate-500 text-xs appearance-none text-center"
                  value={provinceFilter}
                  onChange={(e) => {
                    setProvinceFilter(e.target.value);
                    setDepartmentFilter('All');
                    setLocalityFilter('All');
                  }}
                >
                  <option value="All">Provincia: Todas</option>
                  {locationOptions.provinces.map(p => <option key={p} value={p}>{p}</option>)}
                </select>

                <select 
                  className="px-6 py-4 bg-slate-50 border-none rounded-[2rem] focus:ring-4 focus:ring-blue-500/10 outline-none font-bold text-slate-500 text-xs appearance-none text-center"
                  value={departmentFilter}
                  disabled={provinceFilter === 'All'}
                  onChange={(e) => {
                    setDepartmentFilter(e.target.value);
                    setLocalityFilter('All');
                  }}
                >
                  <option value="All">Departamento: Todos</option>
                  {locationOptions.departments.map(d => <option key={d} value={d}>{d}</option>)}
                </select>

                <select 
                  className="px-6 py-4 bg-slate-50 border-none rounded-[2rem] focus:ring-4 focus:ring-blue-500/10 outline-none font-bold text-slate-500 text-xs appearance-none text-center"
                  value={localityFilter}
                  disabled={departmentFilter === 'All'}
                  onChange={(e) => setLocalityFilter(e.target.value)}
                >
                  <option value="All">Localidad: Todas</option>
                  {locationOptions.localities.map(l => <option key={l} value={l}>{l}</option>)}
                </select>
              </div>
            </div>
          </div>

          {/* Amenities Pill Bar */}
          <div className="flex flex-wrap gap-2 justify-center">
            {allAmenities.slice(0, 10).map(amenity => (
              <button
                key={amenity}
                onClick={() => {
                  setSelectedAmenities(prev => 
                    prev.includes(amenity) ? prev.filter(a => a !== amenity) : [...prev, amenity]
                  );
                }}
                className={`px-5 py-2.5 rounded-full text-[10px] font-black uppercase tracking-widest transition-all ${
                  selectedAmenities.includes(amenity)
                    ? 'bg-slate-900 text-white shadow-lg scale-105'
                    : 'bg-white text-slate-400 hover:bg-slate-50 border border-slate-100 shadow-sm'
                }`}
              >
                {amenity}
              </button>
            ))}
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10">
          {filteredAndSortedProperties.length > 0 ? (
            filteredAndSortedProperties.map(p => (
              <PropertyCard key={p.id} property={p} onClick={(id) => setSelectedPropertyId(id)} />
            ))
          ) : (
            <div className="col-span-full py-32 text-center bg-white rounded-[3rem] border-2 border-dashed border-slate-100">
              <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-6 text-slate-300">
                 <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9.172 9.172a4 4 0 015.656 0M9 10h.01M15 10h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                </svg>
              </div>
              <p className="text-3xl font-black text-slate-900 mb-2">Sin resultados exactos</p>
              <p className="text-slate-400 mb-8">Intenta ajustar los filtros de ubicación o tipo para ver más opciones.</p>
              <button 
                onClick={() => {
                  setSearch(''); 
                  setTypeFilter('All'); 
                  setOpFilter('All'); 
                  setProvinceFilter('All');
                  setDepartmentFilter('All');
                  setLocalityFilter('All');
                  setSelectedAmenities([]); 
                  setSortBy('newest');
                }} 
                className="bg-blue-600 text-white px-10 py-4 rounded-[1.5rem] font-black uppercase tracking-widest hover:bg-blue-700 transition-all shadow-xl shadow-blue-100"
              >
                Resetear Filtros
              </button>
            </div>
          )}
        </div>

        <WhatsAppButton propertyRef="HOME" propertyTitle="Inmobiliaria" variant="floating" />
      </div>
    );
  };

  const renderContent = () => {
    if (view === 'admin') return <AdminDashboard />;
    if (view === 'services') return <ServicesSection />;
    if (view === 'contacto') return <ContactSection />;
    if (view === 'nosotros') return <AboutUsSection />;
    return renderHome();
  };

  return (
    <div className="min-h-screen bg-slate-50/50 selection:bg-blue-100 selection:text-blue-900">
      <nav className="bg-white/80 backdrop-blur-md sticky top-0 z-[100] border-b border-slate-100">
        <div className="max-w-7xl mx-auto px-4 flex justify-between items-center h-24">
          <div className="flex items-center gap-4 cursor-pointer" onClick={() => {setView('home'); setSelectedPropertyId(null);}}>
            <div className="w-12 h-12 bg-red-600 rounded-2xl flex items-center justify-center font-black text-white text-xl shadow-xl shadow-red-200">
              <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6" />
              </svg>
            </div>
            <div className="flex flex-col">
              <span className="font-black text-slate-900 tracking-tighter leading-none text-xl">BERMUDEZ-MOYA</span>
              <span className="text-[10px] font-black text-slate-400 tracking-[0.3em] uppercase">Gestión Inmobiliaria</span>
            </div>
