          <div>
            <h4 className="text-white font-black uppercase tracking-widest text-xs mb-8">Contacto Directo</h4>
            <ul className="space-y-4 text-sm font-medium">
              <li className="text-white italic">Gral. José María Paz Oeste 640</li>
              <li>bermudezmoyap@gmail.com</li>
              <li className="text-red-500 font-bold">+54 264581-3030</li>
            </ul>
          </div>
