              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 19l-7-7m0 0l7-7m-7 7h18" />
            </svg>
            Volver al buscador de propiedades
          </button>

          <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">
            <div className="lg:col-span-2 space-y-12">
              <div className="space-y-4">
                <div className="rounded-[2.5rem] overflow-hidden shadow-2xl aspect-[16/9] bg-slate-100">
                  <img src={selectedProperty.images[0]?.url} alt={selectedProperty.images[0]?.altText} className="w-full h-full object-cover" />
                </div>
                <div className="grid grid-cols-4 gap-4">
                  {selectedProperty.images.slice(1, 5).map(img => (
                    <div key={img.id} className="rounded-2xl overflow-hidden shadow-sm aspect-[4/3] bg-slate-100">
                      <img src={img.url} alt={img.altText} className="w-full h-full object-cover hover:scale-110 transition-transform cursor-pointer" />
                    </div>
                  ))}
                </div>
              </div>

              <div>
                <div className="flex flex-wrap gap-2 mb-6">
                  <span className="bg-blue-600 text-white px-4 py-1.5 rounded-full text-xs font-black uppercase tracking-widest">{selectedProperty.operation}</span>
                  <span className="bg-slate-900 text-white px-4 py-1.5 rounded-full text-xs font-black uppercase tracking-widest">{selectedProperty.type}</span>
                </div>
                <h1 className="text-5xl font-black text-slate-900 mb-4 tracking-tight leading-tight">{selectedProperty.title}</h1>
                <p className="text-2xl text-slate-500 flex items-center gap-3 font-light">
                   <svg className="w-6 h-6 text-blue-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" />
                  </svg>
                  {selectedProperty.location.address}, {selectedProperty.neighborhood || 'Barrio'}
                </p>
              </div>

              <div className="grid grid-cols-2 md:grid-cols-4 gap-4 p-8 bg-slate-50 rounded-[2rem] border border-slate-100">
                <div className="text-center md:border-r border-slate-200">
                  <p className="text-slate-400 text-[10px] font-black uppercase mb-1 tracking-widest">Ambientes</p>
                  <p className="text-3xl font-black text-slate-900">{selectedProperty.features.rooms}</p>
                </div>
                <div className="text-center md:border-r border-slate-200">
                  <p className="text-slate-400 text-[10px] font-black uppercase mb-1 tracking-widest">Baños</p>
                  <p className="text-3xl font-black text-slate-900">{selectedProperty.features.bathrooms}</p>
                </div>
                <div className="text-center md:border-r border-slate-200">
                  <p className="text-slate-400 text-[10px] font-black uppercase mb-1 tracking-widest">Cubiertos</p>
                  <p className="text-3xl font-black text-slate-900">{selectedProperty.features.m2Covered} m²</p>
                </div>
                <div className="text-center">
                  <p className="text-slate-400 text-[10px] font-black uppercase mb-1 tracking-widest">Totales</p>
                  <p className="text-3xl font-black text-slate-900">{selectedProperty.features.m2Total} m²</p>
                </div>
              </div>

              <div className="prose prose-slate max-w-none">
                <h3 className="text-2xl font-black text-slate-900 mb-6">Descripción de la Propiedad</h3>
                <p className="text-slate-600 text-lg leading-relaxed whitespace-pre-line">
                  {selectedProperty.description}
