import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Property, PropertyType, OperationType } from './types';
import { MOCK_PROPERTIES } from './constants';
import PropertyCard from './components/PropertyCard';
import WhatsAppButton from './components/WhatsAppButton';
import AdminDashboard from './components/AdminDashboard';
import StickyContactSidebar from './components/StickyContactSidebar';
import ServicesSection from './components/ServicesSection';
import ContactSection from './components/ContactSection';
import AboutUsSection from './components/AboutUsSection';

type ViewType = 'home' | 'services' | 'admin' | 'nosotros' | 'contacto';
type SortOption = 'newest' | 'oldest' | 'price-asc' | 'price-desc';

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('home');
  const [selectedPropertyId, setSelectedPropertyId] = useState<string | null>(null);
  const [showMap, setShowMap] = useState(false);

  const [search, setSearch] = useState('');
  const [typeFilter, setTypeFilter] = useState<PropertyType | 'All'>('All');
  const [opFilter, setOpFilter] = useState<OperationType | 'All'>('All');
  const [provinceFilter, setProvinceFilter] = useState<string>('All');
  const [departmentFilter, setDepartmentFilter] = useState<string>('All');
  const [localityFilter, setLocalityFilter] = useState<string>('All');
  const [selectedAmenities, setSelectedAmenities] = useState<string[]>([]);
  const [sortBy, setSortBy] = useState<SortOption>('newest');

  const mapRef = useRef<any>(null);

  const clearFilters = () => {
    setSearch('');
    setTypeFilter('All');
    setOpFilter('All');
    setProvinceFilter('All');
    setDepartmentFilter('All');
    setLocalityFilter('All');
    setSelectedAmenities([]);
    setSortBy('newest');
  };

  const locationOptions = useMemo(() => {
    const provinces = new Set<string>();
    const departments = new Set<string>();
    const localities = new Set<string>();

    MOCK_PROPERTIES.forEach(p => {
      if (p.location.province) provinces.add(p.location.province);
      if (provinceFilter === 'All' || p.location.province === provinceFilter) {
        if (p.location.department) departments.add(p.location.department);
      }
      const matchesProv = provinceFilter === 'All' || p.location.province === provinceFilter;
      const matchesDept = departmentFilter === 'All' || p.location.department === departmentFilter;
      if (matchesProv && matchesDept) {
        if (p.location.locality) localities.add(p.location.locality);
      }
    });

    return {
      provinces: Array.from(provinces).sort(),
      departments: Array.from(departments).sort(),
      localities: Array.from(localities).sort()
    };
  }, [provinceFilter, departmentFilter]);

  const allAmenities = useMemo(() => {
    const amenities = new Set<string>();
    MOCK_PROPERTIES.forEach(p => p.features.amenities.forEach(a => amenities.add(a)));
    return Array.from(amenities).sort();
  }, []);

  const filteredAndSortedProperties = useMemo(() => {
    let result = MOCK_PROPERTIES.filter(p => {
      const matchesSearch = p.title.toLowerCase().includes(search.toLowerCase()) || 
                           p.neighborhood?.toLowerCase().includes(search.toLowerCase()) ||
                           p.location.address.toLowerCase().includes(search.toLowerCase());
      const matchesType = typeFilter === 'All' || p.type === typeFilter;
      const matchesOp = opFilter === 'All' || p.operation === opFilter;
      const matchesProv = provinceFilter === 'All' || p.location.province === provinceFilter;
      const matchesDept = departmentFilter === 'All' || p.location.department === departmentFilter;
      const matchesLoc = localityFilter === 'All' || p.location.locality === localityFilter;
      const matchesAmenities = selectedAmenities.length === 0 || 
                               selectedAmenities.every(a => p.features.amenities.includes(a));

      return matchesSearch && matchesType && matchesOp && matchesProv && matchesDept && matchesLoc && matchesAmenities && p.status === 'active';
    });

    return result.sort((a, b) => {
      switch (sortBy) {
        case 'price-asc': return a.price - b.price;
        case 'price-desc': return b.price - a.price;
        case 'oldest': return new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime();
        case 'newest':
        default: return new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime();
      }
    });
  }, [search, typeFilter, opFilter, provinceFilter, departmentFilter, localityFilter, selectedAmenities, sortBy]);

  // Leaflet Map Initialization
  useEffect(() => {
    if (showMap && view === 'home' && !selectedPropertyId) {
      setTimeout(() => {
        if (!mapRef.current) {
          mapRef.current = (window as any).L.map('map').setView([-31.537, -68.525], 13);
          (window as any).L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
            attribution: '&copy; OpenStreetMap contributors'
          }).addTo(mapRef.current);
        } else {
          // Limpiar marcadores existentes
          mapRef.current.eachLayer((layer: any) => {
            if (layer instanceof (window as any).L.Marker) mapRef.current.removeLayer(layer);
          });
        }

        const markers = filteredAndSortedProperties
          .filter(p => p.location.lat && p.location.lng)
          .map(p => {
            const marker = (window as any).L.marker([p.location.lat, p.location.lng])
              .addTo(mapRef.current)
              .bindPopup(`
                <div class="p-1 min-w-[150px]">
                  <img src="${p.images[0]?.url}" class="w-full h-24 object-cover rounded-xl mb-2"/>
                  <h4 class="font-black text-slate-900 text-xs leading-tight mb-1">${p.title}</h4>
                  <p class="text-blue-600 font-black text-xs">${p.currency} ${p.price.toLocaleString()}</p>
                </div>
              `);
            return marker;
          });

        if (markers.length > 0) {
          const group = new (window as any).L.featureGroup(markers);
          mapRef.current.fitBounds(group.getBounds(), { padding: [50, 50] });
        }
      }, 200);
    }

    // Cleanup map when view changes or selectedPropertyId exists
    if (!showMap || !!selectedPropertyId || view !== 'home') {
      if (mapRef.current) {
        mapRef.current.remove();
        mapRef.current = null;
      }
    }
  }, [showMap, filteredAndSortedProperties, selectedPropertyId, view]);

  const selectedProperty = useMemo(() => 
    MOCK_PROPERTIES.find(p => p.id === selectedPropertyId)
  , [selectedPropertyId]);

  const handleAmenityToggle = (amenity: string) => {
    setSelectedAmenities(prev => 
      prev.includes(amenity) ? prev.filter(a => a !== amenity) : [...prev, amenity]
    );
  };

  const renderHome = () => {
    if (selectedProperty) {
      return (
        <div className="max-w-7xl mx-auto p-4 md:p-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <button 
            onClick={() => setSelectedPropertyId(null)}
            className="group flex items-center gap-2 text-blue-600 font-bold mb-8 hover:text-blue-800 transition-colors"
          >
            <svg className="w-5 h-5 transition-transform group-hover:-translate-x-1" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 19l-7-7m0 0l7-7m-7 7h18" />
            </svg>
            Volver al buscador de propiedades
          </button>

          <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">
            <div className="lg:col-span-2 space-y-12">
              <div className="space-y-4">
                <div className="rounded-[2.5rem] overflow-hidden shadow-2xl aspect-[16/9] bg-slate-100">
                  <img src={selectedProperty.images[0]?.url} alt={selectedProperty.images[0]?.altText} className="w-full h-full object-cover" />
                </div>
                <div className="grid grid-cols-4 gap-4">
                  {selectedProperty.images.slice(1, 5).map(img => (
                    <div key={img.id} className="rounded-2xl overflow-hidden shadow-sm aspect-[4/3] bg-slate-100">
                      <img src={img.url} alt={img.altText} className="w-full h-full object-cover hover:scale-110 transition-transform cursor-pointer" />
                    </div>
                  ))}
                </div>
              </div>

              <div>
                <div className="flex flex-wrap gap-2 mb-6">
                  <span className="bg-blue-600 text-white px-4 py-1.5 rounded-full text-xs font-black uppercase tracking-widest">{selectedProperty.operation}</span>
                  <span className="bg-slate-900 text-white px-4 py-1.5 rounded-full text-xs font-black uppercase tracking-widest">{selectedProperty.type}</span>
                </div>
                <h1 className="text-5xl font-black text-slate-900 mb-4 tracking-tight leading-tight">{selectedProperty.title}</h1>
                <p className="text-2xl text-slate-500 flex items-center gap-3 font-light">
                   <svg className="w-6 h-6 text-blue-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" />
                  </svg>
                  {selectedProperty.location.address}, {selectedProperty.neighborhood || 'Barrio'}
                </p>
              </div>

              <div className="grid grid-cols-2 md:grid-cols-4 gap-4 p-8 bg-slate-50 rounded-[2rem] border border-slate-100">
                <div className="text-center md:border-r border-slate-200">
                  <p className="text-slate-400 text-[10px] font-black uppercase mb-1 tracking-widest">Ambientes</p>
                  <p className="text-3xl font-black text-slate-900">{selectedProperty.features.rooms}</p>
                </div>
                <div className="text-center md:border-r border-slate-200">
                  <p className="text-slate-400 text-[10px] font-black uppercase mb-1 tracking-widest">Baños</p>
                  <p className="text-3xl font-black text-slate-900">{selectedProperty.features.bathrooms}</p>
                </div>
                <div className="text-center md:border-r border-slate-200">
                  <p className="text-slate-400 text-[10px] font-black uppercase mb-1 tracking-widest">Cubiertos</p>
                  <p className="text-3xl font-black text-slate-900">{selectedProperty.features.m2Covered} m²</p>
                </div>
                <div className="text-center">
                  <p className="text-slate-400 text-[10px] font-black uppercase mb-1 tracking-widest">Totales</p>
                  <p className="text-3xl font-black text-slate-900">{selectedProperty.features.m2Total} m²</p>
                </div>
              </div>

              <div className="prose prose-slate max-w-none">
                <h3 className="text-2xl font-black text-slate-900 mb-6">Descripción de la Propiedad</h3>
                <p className="text-slate-600 text-lg leading-relaxed whitespace-pre-line">
                  {selectedProperty.description}
                </p>
              </div>
            </div>

            <div className="hidden lg:block relative">
              <StickyContactSidebar property={selectedProperty} />
            </div>
          </div>
        </div>
      );
    }

    return (
      <div className="max-w-7xl mx-auto px-4 md:px-8 py-12">
        <header className="mb-12 text-center">
          <h1 className="text-7xl font-black text-slate-900 mb-6 tracking-tighter leading-none">
            Encuentra tu lugar <br/><span className="text-blue-600">Bermudez-Moya</span>
          </h1>
          <p className="text-xl text-slate-500 max-w-2xl mx-auto font-light leading-relaxed">
            Propiedades exclusivas sincronizadas en tiempo real con CRM Gvamax.
          </p>
        </header>

        {/* Filters Section */}
        <div className="space-y-4 mb-12">
          <div className="bg-white p-4 md:p-6 rounded-[3rem] shadow-2xl shadow-blue-900/5 border border-slate-100">
            <div className="flex flex-col gap-4">
              <div className="flex flex-col lg:flex-row gap-3 items-center w-full">
                <div className="flex-[4] relative w-full">
                  <svg className="w-5 h-5 absolute left-6 top-1/2 -translate-y-1/2 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                  </svg>
                  <input 
                    type="text" 
                    placeholder="Barrio, calle o referencia..."
                    className="w-full pl-14 pr-6 py-5 bg-slate-50 border border-blue-50 rounded-[2rem] focus:ring-4 focus:ring-blue-500/10 transition-all outline-none text-slate-700 font-medium"
                    value={search}
                    onChange={(e) => setSearch(e.target.value)}
                  />
                </div>

                <div className="flex flex-1 gap-2 w-full lg:w-auto">
                  <select 
                    className="flex-1 px-6 py-5 bg-slate-50 border-none rounded-[2rem] focus:ring-4 focus:ring-blue-500/10 outline-none font-bold text-slate-600 text-sm appearance-none text-center"
                    value={typeFilter}
                    onChange={(e) => setTypeFilter(e.target.value as any)}
                  >
                    <option value="All">Tipos</option>
                    {Object.values(PropertyType).map(t => <option key={t} value={t}>{t}</option>)}
                  </select>
                  <select 
                    className="flex-1 px-6 py-5 bg-slate-50 border-none rounded-[2rem] focus:ring-4 focus:ring-blue-500/10 outline-none font-bold text-slate-600 text-sm appearance-none text-center"
                    value={opFilter}
                    onChange={(e) => setOpFilter(e.target.value as any)}
                  >
                    <option value="All">Operación</option>
                    {Object.values(OperationType).map(o => <option key={o} value={o}>{o}</option>)}
                  </select>
                </div>

                <div className="w-full lg:w-48">
                  <select 
                    className="w-full px-6 py-5 bg-blue-600 text-white border-none rounded-[2rem] focus:ring-4 focus:ring-blue-500/10 outline-none font-bold text-sm text-center appearance-none"
                    value={sortBy}
                    onChange={(e) => setSortBy(e.target.value as SortOption)}
                  >
                    <option value="newest">Más recientes</option>
                    <option value="price-asc">Menor Precio</option>
                    <option value="price-desc">Mayor Precio</option>
                  </select>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-4 gap-3 w-full">
                <select className="px-6 py-4 bg-slate-50 border-none rounded-[2rem] focus:ring-4 focus:ring-blue-500/10 outline-none font-bold text-slate-500 text-xs text-center appearance-none" value={provinceFilter} onChange={(e) => {setProvinceFilter(e.target.value); setDepartmentFilter('All'); setLocalityFilter('All');}}>
                  <option value="All">Provincia: Todas</option>
                  {locationOptions.provinces.map(p => <option key={p} value={p}>{p}</option>)}
                </select>
                <select className="px-6 py-4 bg-slate-50 border-none rounded-[2rem] focus:ring-4 focus:ring-blue-500/10 outline-none font-bold text-slate-500 text-xs text-center appearance-none" value={departmentFilter} disabled={provinceFilter === 'All'} onChange={(e) => {setDepartmentFilter(e.target.value); setLocalityFilter('All');}}>
                  <option value="All">Departamento: Todos</option>
                  {locationOptions.departments.map(d => <option key={d} value={d}>{d}</option>)}
                </select>
                <select className="px-6 py-4 bg-slate-50 border-none rounded-[2rem] focus:ring-4 focus:ring-blue-500/10 outline-none font-bold text-slate-500 text-xs text-center appearance-none" value={localityFilter} disabled={departmentFilter === 'All'} onChange={(e) => setLocalityFilter(e.target.value)}>
                  <option value="All">Localidad: Todas</option>
                  {locationOptions.localities.map(l => <option key={l} value={l}>{l}</option>)}
                </select>

                <div className="relative group/amenities">
                  <div className="w-full h-full px-6 py-4 bg-slate-50 border-none rounded-[2rem] font-bold text-slate-500 text-xs text-center flex items-center justify-center gap-2 cursor-pointer hover:bg-slate-100 transition-colors">
                    <span>Amenities {selectedAmenities.length > 0 ? `(${selectedAmenities.length})` : ''}</span>
                    <svg className="w-4 h-4 text-slate-400 group-hover/amenities:rotate-180 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7" /></svg>
                  </div>
                  <div className="absolute top-full left-0 right-0 mt-3 bg-white rounded-[2.5rem] shadow-[0_20px_60px_rgba(0,0,0,0.15)] border border-slate-100 p-6 z-[110] opacity-0 invisible group-hover/amenities:opacity-100 group-hover/amenities:visible transition-all duration-300 translate-y-2 group-hover/amenities:translate-y-0">
                    <div className="grid grid-cols-1 gap-1 max-h-60 overflow-y-auto pr-2 custom-scrollbar">
                      {allAmenities.map(amenity => (
                        <label key={amenity} className="flex items-center gap-3 p-3 rounded-2xl hover:bg-blue-50 cursor-pointer transition-colors group/item">
                          <input type="checkbox" checked={selectedAmenities.includes(amenity)} onChange={() => handleAmenityToggle(amenity)} className="w-4 h-4 rounded text-blue-600 focus:ring-blue-500 border-slate-300" />
                          <span className="text-xs font-bold text-slate-700 group-hover/item:text-blue-700">{amenity}</span>
                        </label>
                      ))}
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>

          <div className="flex justify-between items-center px-4">
            <div className="flex gap-4">
              <button 
                onClick={() => setShowMap(!showMap)}
                className={`flex items-center gap-2 px-8 py-3 rounded-full text-xs font-black uppercase tracking-widest transition-all ${showMap ? 'bg-slate-900 text-white shadow-xl' : 'bg-white text-slate-600 border border-slate-200 shadow-sm'}`}
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 20l-5.447-2.724A2 2 0 013 15.382V6c0-1.1.9-2 2-2h14a2 2 0 012 2v9.382a2 2 0 01-1.553 1.894L15 20l-3-1.5-3 1.5z" /></svg>
                {showMap ? 'Vista Lista' : 'Vista Mapa'}
              </button>
              {(search || typeFilter !== 'All' || opFilter !== 'All' || provinceFilter !== 'All' || selectedAmenities.length > 0) && (
                <button 
                  onClick={clearFilters}
                  className="flex items-center gap-2 px-6 py-2.5 rounded-full text-xs font-black uppercase tracking-widest bg-red-50 text-red-600 border border-red-100 hover:bg-red-100 transition-all"
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
                  Eliminar Filtros
                </button>
              )}
            </div>
            <p className="hidden md:block text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">{filteredAndSortedProperties.length} Propiedades encontradas</p>
          </div>
        </div>

        {/* Home Content Body */}
        <div className="animate-in fade-in duration-500">
          {showMap ? (
            <div className="flex flex-col lg:flex-row gap-8 h-[calc(100vh-280px)] min-h-[600px]">
              {/* List Sidebar in Map Mode */}
              <div className="lg:w-1/3 xl:w-1/4 h-full overflow-y-auto pr-2 custom-scrollbar space-y-4">
                {filteredAndSortedProperties.length > 0 ? (
                  filteredAndSortedProperties.map(p => (
                    <PropertyCard key={p.id} property={p} onClick={setSelectedPropertyId} compact />
                  ))
                ) : (
                  <div className="bg-white p-12 rounded-[2rem] text-center border-2 border-dashed border-slate-100">
                    <p className="font-bold text-slate-400">Sin resultados</p>
                  </div>
                )}
              </div>
              {/* Map View */}
              <div className="lg:w-2/3 xl:w-3/4 h-full relative">
                <div id="map" className="h-full rounded-[3rem] shadow-2xl shadow-blue-900/10 border-8 border-white"></div>
              </div>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10">
              {filteredAndSortedProperties.length > 0 ? (
                filteredAndSortedProperties.map(p => (
                  <PropertyCard key={p.id} property={p} onClick={setSelectedPropertyId} />
                ))
              ) : (
                <div className="col-span-full py-32 text-center bg-white rounded-[3rem] border-2 border-dashed border-slate-100">
                  <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-6 text-slate-300">
                    <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9.172 9.172a4 4 0 015.656 0M9 10h.01M15 10h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                    </svg>
                  </div>
                  <p className="text-3xl font-black text-slate-900 mb-2">Sin resultados exactos</p>
                  <p className="text-slate-400 mb-8">Intenta ajustar los filtros para ver más opciones.</p>
                  <button onClick={clearFilters} className="bg-blue-600 text-white px-10 py-4 rounded-[1.5rem] font-black uppercase tracking-widest hover:bg-blue-700 transition-all shadow-xl shadow-blue-100">Resetear Búsqueda</button>
                </div>
              )}
            </div>
          )}
        </div>

        <WhatsAppButton propertyRef="HOME" propertyTitle="Inmobiliaria" variant="floating" />
      </div>
    );
  };

  const renderContent = () => {
    if (view === 'admin') return <AdminDashboard />;
    if (view === 'services') return <ServicesSection />;
    if (view === 'contacto') return <ContactSection />;
    if (view === 'nosotros') return <AboutUsSection />;
    return renderHome();
  };

  return (
    <div className="min-h-screen bg-slate-50/50 selection:bg-blue-100 selection:text-blue-900">
      <nav className="bg-white/80 backdrop-blur-md sticky top-0 z-[100] border-b border-slate-100">
        <div className="max-w-7xl mx-auto px-4 flex justify-between items-center h-24">
          <div className="flex items-center gap-4 cursor-pointer" onClick={() => {setView('home'); setSelectedPropertyId(null); setShowMap(false);}}>
            <div className="w-12 h-12 bg-red-600 rounded-2xl flex items-center justify-center font-black text-white text-xl shadow-xl shadow-red-200">BM</div>
            <div className="flex flex-col">
              <span className="font-black text-slate-900 tracking-tighter leading-none text-xl">BERMUDEZ-MOYA</span>
              <span className="text-[10px] font-black text-slate-400 tracking-[0.3em] uppercase">Gestión Inmobiliaria</span>
            </div>
          </div>
          <div className="flex items-center gap-8">
            <div className="hidden md:flex gap-8">
               <button onClick={() => {setView('home'); setSelectedPropertyId(null); setShowMap(false);}} className={`text-xs font-black uppercase tracking-widest transition-colors ${view === 'home' ? 'text-red-600' : 'text-slate-400 hover:text-slate-900'}`}>Propiedades</button>
               <button onClick={() => setView('services')} className={`text-xs font-black uppercase tracking-widest transition-colors ${view === 'services' ? 'text-red-600' : 'text-slate-400 hover:text-slate-900'}`}>Servicios</button>
               <button onClick={() => setView('contacto')} className={`text-xs font-black uppercase tracking-widest transition-colors ${view === 'contacto' ? 'text-red-600' : 'text-slate-400 hover:text-slate-900'}`}>Contacto</button>
               <button onClick={() => setView('nosotros')} className={`text-xs font-black uppercase tracking-widest transition-colors ${view === 'nosotros' ? 'text-red-600' : 'text-slate-400 hover:text-slate-900'}`}>Nosotros</button>
            </div>
            <button onClick={() => setView('admin')} className={`text-[10px] font-black uppercase tracking-widest px-5 py-2.5 rounded-xl transition-all ${view === 'admin' ? 'bg-slate-900 text-white shadow-xl' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}>Panel Admin</button>
          </div>
        </div>
      </nav>
      <main className="pb-20">{renderContent()}</main>
      <footer className="bg-slate-900 text-slate-400 py-24">
        <div className="max-w-7xl mx-auto px-8 grid grid-cols-1 md:grid-cols-4 gap-20">
          <div className="col-span-1 md:col-span-2 space-y-8">
              <div className="flex items-center gap-4">
                <div className="w-10 h-10 bg-red-600 rounded-xl flex items-center justify-center font-black text-white shadow-lg">BM</div>
                <span className="font-black tracking-tighter text-white text-2xl">BERMUDEZ-MOYA</span>
              </div>
              <p className="max-w-md text-lg leading-relaxed font-light">Innovación inmobiliaria con tecnología avanzada de sincronización Gvamax.</p>
          </div>
          <div>
            <h4 className="text-white font-black uppercase tracking-widest text-xs mb-8">Empresa</h4>
            <ul className="space-y-4 text-sm font-medium">
              <li className="hover:text-white cursor-pointer" onClick={() => setView('nosotros')}>Nosotros</li>
              <li className="hover:text-white cursor-pointer" onClick={() => setView('services')}>Servicios</li>
              <li className="hover:text-white cursor-pointer" onClick={() => setView('contacto')}>Contacto</li>
            </ul>
          </div>
          <div>
            <h4 className="text-white font-black uppercase tracking-widest text-xs mb-8">Legal</h4>
            <ul className="space-y-4 text-sm font-medium">
              <li>Términos y Condiciones</li>
              <li>Política de Privacidad</li>
              <li>Cámaras Inmobiliarias</li>
            </ul>
          </div>
        </div>
        <div className="max-w-7xl mx-auto px-8 mt-20 pt-8 border-t border-slate-800 text-center text-[10px] font-black uppercase tracking-[0.4em] opacity-50">© 2024 Bermudez-Moya | Powered by High-Sync Tech</div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Property, PropertyType, OperationType } from './types';
import { MOCK_PROPERTIES } from './constants';
import PropertyCard from './components/PropertyCard';
import WhatsAppButton from './components/WhatsAppButton';
import AdminDashboard from './components/AdminDashboard';
import StickyContactSidebar from './components/StickyContactSidebar';
import ServicesSection from './components/ServicesSection';
import ContactSection from './components/ContactSection';
import AboutUsSection from './components/AboutUsSection';

type ViewType = 'home' | 'services' | 'admin' | 'nosotros' | 'contacto';
type SortOption = 'newest' | 'oldest' | 'price-asc' | 'price-desc';

const App: React.FC = () => {
  const [view, setView] = useState<ViewType>('home');
  const [selectedPropertyId, setSelectedPropertyId] = useState<string | null>(null);
  const [showMap, setShowMap] = useState(false);

  const [search, setSearch] = useState('');
  const [typeFilter, setTypeFilter] = useState<PropertyType | 'All'>('All');
  const [opFilter, setOpFilter] = useState<OperationType | 'All'>('All');
  const [provinceFilter, setProvinceFilter] = useState<string>('All');
  const [departmentFilter, setDepartmentFilter] = useState<string>('All');
  const [localityFilter, setLocalityFilter] = useState<string>('All');
  const [selectedAmenities, setSelectedAmenities] = useState<string[]>([]);
  const [sortBy, setSortBy] = useState<SortOption>('newest');

  const mapRef = useRef<any>(null);

  const clearFilters = () => {
    setSearch('');
    setTypeFilter('All');
    setOpFilter('All');
    setProvinceFilter('All');
    setDepartmentFilter('All');
    setLocalityFilter('All');
    setSelectedAmenities([]);
    setSortBy('newest');
  };

  const locationOptions = useMemo(() => {
    const provinces = new Set<string>();
    const departments = new Set<string>();
    const localities = new Set<string>();

    MOCK_PROPERTIES.forEach(p => {
      if (p.location.province) provinces.add(p.location.province);
      if (provinceFilter === 'All' || p.location.province === provinceFilter) {
        if (p.location.department) departments.add(p.location.department);
      }
      const matchesProv = provinceFilter === 'All' || p.location.province === provinceFilter;
      const matchesDept = departmentFilter === 'All' || p.location.department === departmentFilter;
      if (matchesProv && matchesDept) {
        if (p.location.locality) localities.add(p.location.locality);
      }
    });

    return {
      provinces: Array.from(provinces).sort(),
      departments: Array.from(departments).sort(),
      localities: Array.from(localities).sort()
    };
  }, [provinceFilter, departmentFilter]);

  const allAmenities = useMemo(() => {
    const amenities = new Set<string>();
    MOCK_PROPERTIES.forEach(p => p.features.amenities.forEach(a => amenities.add(a)));
    return Array.from(amenities).sort();
  }, []);

  const filteredAndSortedProperties = useMemo(() => {
    let result = MOCK_PROPERTIES.filter(p => {
      const matchesSearch = p.title.toLowerCase().includes(search.toLowerCase()) || 
                           p.neighborhood?.toLowerCase().includes(search.toLowerCase()) ||
                           p.location.address.toLowerCase().includes(search.toLowerCase());
      const matchesType = typeFilter === 'All' || p.type === typeFilter;
      const matchesOp = opFilter === 'All' || p.operation === opFilter;
      const matchesProv = provinceFilter === 'All' || p.location.province === provinceFilter;
      const matchesDept = departmentFilter === 'All' || p.location.department === departmentFilter;
      const matchesLoc = localityFilter === 'All' || p.location.locality === localityFilter;
      const matchesAmenities = selectedAmenities.length === 0 || 
                               selectedAmenities.every(a => p.features.amenities.includes(a));

      return matchesSearch && matchesType && matchesOp && matchesProv && matchesDept && matchesLoc && matchesAmenities && p.status === 'active';
    });

    return result.sort((a, b) => {
      switch (sortBy) {
        case 'price-asc': return a.price - b.price;
        case 'price-desc': return b.price - a.price;
        case 'oldest': return new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime();
        case 'newest':
        default: return new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime();
      }
    });
  }, [search, typeFilter, opFilter, provinceFilter, departmentFilter, localityFilter, selectedAmenities, sortBy]);

  // Leaflet Map Initialization
  useEffect(() => {
    if (showMap && view === 'home' && !selectedPropertyId) {
      setTimeout(() => {
        if (!mapRef.current) {
          mapRef.current = (window as any).L.map('map').setView([-31.537, -68.525], 13);
          (window as any).L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
            attribution: '&copy; OpenStreetMap contributors'
          }).addTo(mapRef.current);
        } else {
          // Limpiar marcadores existentes
          mapRef.current.eachLayer((layer: any) => {
            if (layer instanceof (window as any).L.Marker) mapRef.current.removeLayer(layer);
          });
        }

        const markers = filteredAndSortedProperties
          .filter(p => p.location.lat && p.location.lng)
          .map(p => {
            const marker = (window as any).L.marker([p.location.lat, p.location.lng])
              .addTo(mapRef.current)
              .bindPopup(`
                <div class="p-1 min-w-[150px]">
                  <img src="${p.images[0]?.url}" class="w-full h-24 object-cover rounded-xl mb-2"/>
                  <h4 class="font-black text-slate-900 text-xs leading-tight mb-1">${p.title}</h4>
                  <p class="text-blue-600 font-black text-xs">${p.currency} ${p.price.toLocaleString()}</p>
                </div>
              `);
            return marker;
          });

        if (markers.length > 0) {
          const group = new (window as any).L.featureGroup(markers);
          mapRef.current.fitBounds(group.getBounds(), { padding: [50, 50] });
        }
      }, 200);
    }

    // Cleanup map when view changes or selectedPropertyId exists
    if (!showMap || !!selectedPropertyId || view !== 'home') {
      if (mapRef.current) {
        mapRef.current.remove();
        mapRef.current = null;
      }
    }
  }, [showMap, filteredAndSortedProperties, selectedPropertyId, view]);

  const selectedProperty = useMemo(() => 
    MOCK_PROPERTIES.find(p => p.id === selectedPropertyId)
  , [selectedPropertyId]);

  const handleAmenityToggle = (amenity: string) => {
    setSelectedAmenities(prev => 
      prev.includes(amenity) ? prev.filter(a => a !== amenity) : [...prev, amenity]
    );
  };

  const renderHome = () => {
    if (selectedProperty) {
      return (
        <div className="max-w-7xl mx-auto p-4 md:p-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <button 
            onClick={() => setSelectedPropertyId(null)}
            className="group flex items-center gap-2 text-blue-600 font-bold mb-8 hover:text-blue-800 transition-colors"
          >
            <svg className="w-5 h-5 transition-transform group-hover:-translate-x-1" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 19l-7-7m0 0l7-7m-7 7h18" />
            </svg>
            Volver al buscador de propiedades
          </button>

          <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">
            <div className="lg:col-span-2 space-y-12">
              <div className="space-y-4">
                <div className="rounded-[2.5rem] overflow-hidden shadow-2xl aspect-[16/9] bg-slate-100">
                  <img src={selectedProperty.images[0]?.url} alt={selectedProperty.images[0]?.altText} className="w-full h-full object-cover" />
                </div>
                <div className="grid grid-cols-4 gap-4">
                  {selectedProperty.images.slice(1, 5).map(img => (
                    <div key={img.id} className="rounded-2xl overflow-hidden shadow-sm aspect-[4/3] bg-slate-100">
                      <img src={img.url} alt={img.altText} className="w-full h-full object-cover hover:scale-110 transition-transform cursor-pointer" />
                    </div>
                  ))}
                </div>
              </div>

              <div>
                <div className="flex flex-wrap gap-2 mb-6">
                  <span className="bg-blue-600 text-white px-4 py-1.5 rounded-full text-xs font-black uppercase tracking-widest">{selectedProperty.operation}</span>
                  <span className="bg-slate-900 text-white px-4 py-1.5 rounded-full text-xs font-black uppercase tracking-widest">{selectedProperty.type}</span>
                </div>
                <h1 className="text-5xl font-black text-slate-900 mb-4 tracking-tight leading-tight">{selectedProperty.title}</h1>
                <p className="text-2xl text-slate-500 flex items-center gap-3 font-light">
                   <svg className="w-6 h-6 text-blue-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" />
                  </svg>
                  {selectedProperty.location.address}, {selectedProperty.neighborhood || 'Barrio'}
                </p>
              </div>

              <div className="grid grid-cols-2 md:grid-cols-4 gap-4 p-8 bg-slate-50 rounded-[2rem] border border-slate-100">
                <div className="text-center md:border-r border-slate-200">
                  <p className="text-slate-400 text-[10px] font-black uppercase mb-1 tracking-widest">Ambientes</p>
                  <p className="text-3xl font-black text-slate-900">{selectedProperty.features.rooms}</p>
                </div>
                <div className="text-center md:border-r border-slate-200">
                  <p className="text-slate-400 text-[10px] font-black uppercase mb-1 tracking-widest">Baños</p>
                  <p className="text-3xl font-black text-slate-900">{selectedProperty.features.bathrooms}</p>
                </div>
                <div className="text-center md:border-r border-slate-200">
                  <p className="text-slate-400 text-[10px] font-black uppercase mb-1 tracking-widest">Cubiertos</p>
                  <p className="text-3xl font-black text-slate-900">{selectedProperty.features.m2Covered} m²</p>
                </div>
                <div className="text-center">
                  <p className="text-slate-400 text-[10px] font-black uppercase mb-1 tracking-widest">Totales</p>
                  <p className="text-3xl font-black text-slate-900">{selectedProperty.features.m2Total} m²</p>
                </div>
              </div>

              <div className="prose prose-slate max-w-none">
                <h3 className="text-2xl font-black text-slate-900 mb-6">Descripción de la Propiedad</h3>
                <p className="text-slate-600 text-lg leading-relaxed whitespace-pre-line">
                  {selectedProperty.description}
                </p>
              </div>
            </div>

            <div className="hidden lg:block relative">
              <StickyContactSidebar property={selectedProperty} />
            </div>
          </div>
        </div>
      );
    }

    return (
      <div className="max-w-7xl mx-auto px-4 md:px-8 py-12">
        <header className="mb-12 text-center">
          <h1 className="text-7xl font-black text-slate-900 mb-6 tracking-tighter leading-none">
            Encuentra tu lugar <br/><span className="text-blue-600">Bermudez-Moya</span>
          </h1>
          <p className="text-xl text-slate-500 max-w-2xl mx-auto font-light leading-relaxed">
            Propiedades exclusivas sincronizadas en tiempo real con CRM Gvamax.
          </p>
        </header>

        {/* Filters Section */}
        <div className="space-y-4 mb-12">
          <div className="bg-white p-4 md:p-6 rounded-[3rem] shadow-2xl shadow-blue-900/5 border border-slate-100">
            <div className="flex flex-col gap-4">
              <div className="flex flex-col lg:flex-row gap-3 items-center w-full">
                <div className="flex-[4] relative w-full">
                  <svg className="w-5 h-5 absolute left-6 top-1/2 -translate-y-1/2 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                  </svg>
                  <input 
                    type="text" 
                    placeholder="Barrio, calle o referencia..."
                    className="w-full pl-14 pr-6 py-5 bg-slate-50 border border-blue-50 rounded-[2rem] focus:ring-4 focus:ring-blue-500/10 transition-all outline-none text-slate-700 font-medium"
                    value={search}
                    onChange={(e) => setSearch(e.target.value)}
                  />
                </div>

                <div className="flex flex-1 gap-2 w-full lg:w-auto">
                  <select 
                    className="flex-1 px-6 py-5 bg-slate-50 border-none rounded-[2rem] focus:ring-4 focus:ring-blue-500/10 outline-none font-bold text-slate-600 text-sm appearance-none text-center"
                    value={typeFilter}
                    onChange={(e) => setTypeFilter(e.target.value as any)}
                  >
                    <option value="All">Tipos</option>
                    {Object.values(PropertyType).map(t => <option key={t} value={t}>{t}</option>)}
                  </select>
                  <select 
                    className="flex-1 px-6 py-5 bg-slate-50 border-none rounded-[2rem] focus:ring-4 focus:ring-blue-500/10 outline-none font-bold text-slate-600 text-sm appearance-none text-center"
                    value={opFilter}
                    onChange={(e) => setOpFilter(e.target.value as any)}
                  >
                    <option value="All">Operación</option>
                    {Object.values(OperationType).map(o => <option key={o} value={o}>{o}</option>)}
                  </select>
                </div>

                <div className="w-full lg:w-48">
                  <select 
                    className="w-full px-6 py-5 bg-blue-600 text-white border-none rounded-[2rem] focus:ring-4 focus:ring-blue-500/10 outline-none font-bold text-sm text-center appearance-none"
                    value={sortBy}
                    onChange={(e) => setSortBy(e.target.value as SortOption)}
                  >
                    <option value="newest">Más recientes</option>
                    <option value="price-asc">Menor Precio</option>
                    <option value="price-desc">Mayor Precio</option>
                  </select>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-4 gap-3 w-full">
                <select className="px-6 py-4 bg-slate-50 border-none rounded-[2rem] focus:ring-4 focus:ring-blue-500/10 outline-none font-bold text-slate-500 text-xs text-center appearance-none" value={provinceFilter} onChange={(e) => {setProvinceFilter(e.target.value); setDepartmentFilter('All'); setLocalityFilter('All');}}>
                  <option value="All">Provincia: Todas</option>
                  {locationOptions.provinces.map(p => <option key={p} value={p}>{p}</option>)}
                </select>
                <select className="px-6 py-4 bg-slate-50 border-none rounded-[2rem] focus:ring-4 focus:ring-blue-500/10 outline-none font-bold text-slate-500 text-xs text-center appearance-none" value={departmentFilter} disabled={provinceFilter === 'All'} onChange={(e) => {setDepartmentFilter(e.target.value); setLocalityFilter('All');}}>
                  <option value="All">Departamento: Todos</option>
                  {locationOptions.departments.map(d => <option key={d} value={d}>{d}</option>)}
                </select>
                <select className="px-6 py-4 bg-slate-50 border-none rounded-[2rem] focus:ring-4 focus:ring-blue-500/10 outline-none font-bold text-slate-500 text-xs text-center appearance-none" value={localityFilter} disabled={departmentFilter === 'All'} onChange={(e) => setLocalityFilter(e.target.value)}>
                  <option value="All">Localidad: Todas</option>
                  {locationOptions.localities.map(l => <option key={l} value={l}>{l}</option>)}
                </select>

                <div className="relative group/amenities">
                  <div className="w-full h-full px-6 py-4 bg-slate-50 border-none rounded-[2rem] font-bold text-slate-500 text-xs text-center flex items-center justify-center gap-2 cursor-pointer hover:bg-slate-100 transition-colors">
                    <span>Amenities {selectedAmenities.length > 0 ? `(${selectedAmenities.length})` : ''}</span>
                    <svg className="w-4 h-4 text-slate-400 group-hover/amenities:rotate-180 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7" /></svg>
                  </div>
                  <div className="absolute top-full left-0 right-0 mt-3 bg-white rounded-[2.5rem] shadow-[0_20px_60px_rgba(0,0,0,0.15)] border border-slate-100 p-6 z-[110] opacity-0 invisible group-hover/amenities:opacity-100 group-hover/amenities:visible transition-all duration-300 translate-y-2 group-hover/amenities:translate-y-0">
                    <div className="grid grid-cols-1 gap-1 max-h-60 overflow-y-auto pr-2 custom-scrollbar">
                      {allAmenities.map(amenity => (
                        <label key={amenity} className="flex items-center gap-3 p-3 rounded-2xl hover:bg-blue-50 cursor-pointer transition-colors group/item">
                          <input type="checkbox" checked={selectedAmenities.includes(amenity)} onChange={() => handleAmenityToggle(amenity)} className="w-4 h-4 rounded text-blue-600 focus:ring-blue-500 border-slate-300" />
                          <span className="text-xs font-bold text-slate-700 group-hover/item:text-blue-700">{amenity}</span>
                        </label>
                      ))}
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>

          <div className="flex justify-between items-center px-4">
            <div className="flex gap-4">
              <button 
                onClick={() => setShowMap(!showMap)}
                className={`flex items-center gap-2 px-8 py-3 rounded-full text-xs font-black uppercase tracking-widest transition-all ${showMap ? 'bg-slate-900 text-white shadow-xl hover:bg-slate-800' : 'bg-red-600 text-white shadow-xl shadow-red-100 hover:bg-red-700 border-none'}`}
              >
                <svg className={`w-4 h-4 ${showMap ? 'text-white' : 'text-white'}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 20l-5.447-2.724A2 2 0 013 15.382V6c0-1.1.9-2 2-2h14a2 2 0 012 2v9.382a2 2 0 01-1.553 1.894L15 20l-3-1.5-3 1.5z" />
                </svg>
                {showMap ? 'Vista Lista' : 'Vista Mapa'}
              </button>
              {(search || typeFilter !== 'All' || opFilter !== 'All' || provinceFilter !== 'All' || selectedAmenities.length > 0) && (
                <button 
                  onClick={clearFilters}
                  className="flex items-center gap-2 px-6 py-2.5 rounded-full text-xs font-black uppercase tracking-widest bg-red-50 text-red-600 border border-red-100 hover:bg-red-100 transition-all"
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
                  Eliminar Filtros
                </button>
              )}
            </div>
            <p className="hidden md:block text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">{filteredAndSortedProperties.length} Propiedades encontradas</p>
          </div>
        </div>

        {/* Home Content Body */}
        <div className="animate-in fade-in duration-500">
          {showMap ? (
            <div className="flex flex-col lg:flex-row gap-8 h-[calc(100vh-280px)] min-h-[600px]">
              {/* List Sidebar in Map Mode */}
              <div className="lg:w-1/3 xl:w-1/4 h-full overflow-y-auto pr-2 custom-scrollbar space-y-4">
                {filteredAndSortedProperties.length > 0 ? (
                  filteredAndSortedProperties.map(p => (
                    <PropertyCard key={p.id} property={p} onClick={setSelectedPropertyId} compact />
                  ))
                ) : (
                  <div className="bg-white p-12 rounded-[2rem] text-center border-2 border-dashed border-slate-100">
                    <p className="font-bold text-slate-400">Sin resultados</p>
                  </div>
                )}
              </div>
              {/* Map View */}
              <div className="lg:w-2/3 xl:w-3/4 h-full relative">
                <div id="map" className="h-full rounded-[3rem] shadow-2xl shadow-blue-900/10 border-8 border-white"></div>
              </div>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10">
              {filteredAndSortedProperties.length > 0 ? (
                filteredAndSortedProperties.map(p => (
                  <PropertyCard key={p.id} property={p} onClick={setSelectedPropertyId} />
                ))
              ) : (
                <div className="col-span-full py-32 text-center bg-white rounded-[3rem] border-2 border-dashed border-slate-100">
                  <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-6 text-slate-300">
                    <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9.172 9.172a4 4 0 015.656 0M9 10h.01M15 10h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                    </svg>
                  </div>
                  <p className="text-3xl font-black text-slate-900 mb-2">Sin resultados exactos</p>
                  <p className="text-slate-400 mb-8">Intenta ajustar los filtros para ver más opciones.</p>
                  <button onClick={clearFilters} className="bg-blue-600 text-white px-10 py-4 rounded-[1.5rem] font-black uppercase tracking-widest hover:bg-blue-700 transition-all shadow-xl shadow-blue-100">Resetear Búsqueda</button>
                </div>
              )}
            </div>
          )}
        </div>

        <WhatsAppButton propertyRef="HOME" propertyTitle="Inmobiliaria" variant="floating" />
      </div>
    );
  };

  const renderContent = () => {
    if (view === 'admin') return <AdminDashboard />;
    if (view === 'services') return <ServicesSection />;
    if (view === 'contacto') return <ContactSection />;
    if (view === 'nosotros') return <AboutUsSection />;
    return renderHome();
  };

  return (
    <div className="min-h-screen bg-slate-50/50 selection:bg-blue-100 selection:text-blue-900">
      <nav className="bg-white/80 backdrop-blur-md sticky top-0 z-[100] border-b border-slate-100">
        <div className="max-w-7xl mx-auto px-4 flex justify-between items-center h-24">
          <div className="flex items-center gap-4 cursor-pointer" onClick={() => {setView('home'); setSelectedPropertyId(null); setShowMap(false);}}>
            <div className="w-12 h-12 bg-red-600 rounded-2xl flex items-center justify-center font-black text-white text-xl shadow-xl shadow-red-200">BM</div>
            <div className="flex flex-col">
              <span className="font-black text-slate-900 tracking-tighter leading-none text-xl">BERMUDEZ-MOYA</span>
              <span className="text-[10px] font-black text-slate-400 tracking-[0.3em] uppercase">Gestión Inmobiliaria</span>
            </div>
          </div>
          <div className="flex items-center gap-8">
            <div className="hidden md:flex gap-8">
               <button onClick={() => {setView('home'); setSelectedPropertyId(null); setShowMap(false);}} className={`text-xs font-black uppercase tracking-widest transition-colors ${view === 'home' ? 'text-red-600' : 'text-slate-400 hover:text-slate-900'}`}>Propiedades</button>
               <button onClick={() => setView('services')} className={`text-xs font-black uppercase tracking-widest transition-colors ${view === 'services' ? 'text-red-600' : 'text-slate-400 hover:text-slate-900'}`}>Servicios</button>
               <button onClick={() => setView('contacto')} className={`text-xs font-black uppercase tracking-widest transition-colors ${view === 'contacto' ? 'text-red-600' : 'text-slate-400 hover:text-slate-900'}`}>Contacto</button>
               <button onClick={() => setView('nosotros')} className={`text-xs font-black uppercase tracking-widest transition-colors ${view === 'nosotros' ? 'text-red-600' : 'text-slate-400 hover:text-slate-900'}`}>Nosotros</button>
            </div>
            <button onClick={() => setView('admin')} className={`text-[10px] font-black uppercase tracking-widest px-5 py-2.5 rounded-xl transition-all ${view === 'admin' ? 'bg-slate-900 text-white shadow-xl' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}>Panel Admin</button>
          </div>
        </div>
      </nav>
      <main className="pb-20">{renderContent()}</main>
      <footer className="bg-slate-900 text-slate-400 py-24">
        <div className="max-w-7xl mx-auto px-8 grid grid-cols-1 md:grid-cols-4 gap-20">
          <div className="col-span-1 md:col-span-2 space-y-8">
              <div className="flex items-center gap-4">
                <div className="w-10 h-10 bg-red-600 rounded-xl flex items-center justify-center font-black text-white shadow-lg">BM</div>
                <span className="font-black tracking-tighter text-white text-2xl">BERMUDEZ-MOYA</span>
              </div>
              <p className="max-w-md text-lg leading-relaxed font-light">Innovación inmobiliaria con tecnología avanzada de sincronización Gvamax.</p>
          </div>
          <div>
            <h4 className="text-white font-black uppercase tracking-widest text-xs mb-8">Empresa</h4>
            <ul className="space-y-4 text-sm font-medium">
              <li className="hover:text-white cursor-pointer" onClick={() => setView('nosotros')}>Nosotros</li>
              <li className="hover:text-white cursor-pointer" onClick={() => setView('services')}>Servicios</li>
              <li className="hover:text-white cursor-pointer" onClick={() => setView('contacto')}>Contacto</li>
            </ul>
          </div>
          <div>
            <h4 className="text-white font-black uppercase tracking-widest text-xs mb-8">Legal</h4>
            <ul className="space-y-4 text-sm font-medium">
              <li>Términos y Condiciones</li>
              <li>Política de Privacidad</li>
              <li>Cámaras Inmobiliarias</li>
            </ul>
          </div>
        </div>
        <div className="max-w-7xl mx-auto px-8 mt-20 pt-8 border-t border-slate-800 text-center text-[10px] font-black uppercase tracking-[0.4em] opacity-50">© 2024 Bermudez-Moya | Powered by High-Sync Tech</div>
      </footer>
    </div>
  );
};

export default App;

