import React, { useState, useMemo } from 'react';
import { Property, PropertyType, OperationType, SyncStats, Lead } from '../types';
import { MOCK_PROPERTIES, MOCK_LEADS } from '../constants';
import { syncWithGvamax, extractCoordsFromUrl } from '../services/syncService';
import { renameImageForSEO, generateAltText } from '../services/imageService';

type AdminView = 'overview' | 'properties' | 'leads' | 'sync' | 'settings';

const AdminDashboard: React.FC = () => {
  const [activeView, setActiveView] = useState<AdminView>('overview');
  const [properties, setProperties] = useState<Property[]>(MOCK_PROPERTIES);
  const [leads, setLeads] = useState<Lead[]>(MOCK_LEADS);
  const [isSyncing, setIsSyncing] = useState(false);
  const [syncHistory, setSyncHistory] = useState<SyncStats[]>([]);
  const [editingProperty, setEditingProperty] = useState<Property | null>(null);
  const [selectedLead, setSelectedLead] = useState<Lead | null>(null);

  const stats = useMemo(() => {
    return {
      total: properties.length,
      active: properties.filter(p => p.status === 'active').length,
      leads: leads.length,
      newLeads: leads.filter(l => l.status === 'new').length,
      views: properties.reduce((acc, p) => acc + p.viewsCount, 0),
    };
  }, [properties, leads]);

  const handleSync = async () => {
    setIsSyncing(true);
    try {
      const result = await syncWithGvamax();
      setSyncHistory([result, ...syncHistory]);
      // En un entorno real esto actualizaría el estado global de propiedades
    } catch (e) {
      console.error("Error en la sincronización.");
    } finally {
      setIsSyncing(false);
    }
  };

  const updateLeadStatus = (leadId: string, newStatus: Lead['status']) => {
    setLeads(leads.map(l => l.id === leadId ? { ...l, status: newStatus } : l));
  };

  const handleDuplicate = (id: string) => {
    const property = properties.find(p => p.id === id);
    if (property) {
      const duplicated = {
        ...property,
        id: Math.random().toString(36).substring(7),
        ref: `${property.ref}-CLONE-${Math.floor(Math.random() * 1000)}`,
        title: `${property.title} (COPIA)`,
        createdAt: new Date().toISOString(),
        viewsCount: 0,
        leadsCount: 0
      };
      setProperties([duplicated, ...properties]);
    }
  };

  const handleArchive = (id: string) => {
    if (confirm("¿Seguro que desea archivar esta propiedad? Dejará de ser visible en el sitio público.")) {
      setProperties(properties.map(p => p.id === id ? { ...p, status: 'archived' as const } : p));
    }
  };

  // Fix for line 271: added handleManualUpload function
  const handleManualUpload = () => {
    const newProperty: Property = {
      id: Math.random().toString(36).substring(7),
      externalId: '',
      ref: `REF-NEW-${Math.floor(Math.random() * 1000)}`,
      title: '',
      description: '',
      type: PropertyType.APARTMENT,
      operation: OperationType.SALE,
      price: 0,
      currency: 'USD',
      neighborhood: '',
      location: {
        address: '',
        city: 'San Juan',
        province: 'San Juan',
        department: '',
        locality: '',
      },
      features: {
        rooms: 0,
        bedrooms: 0,
        bathrooms: 0,
        m2Total: 0,
        m2Covered: 0,
        amenities: []
      },
      images: [],
      status: 'active',
      viewsCount: 0,
      leadsCount: 0,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      lastSyncAt: new Date().toISOString()
    };
    setEditingProperty(newProperty);
  };

  // Fixed handleSaveProperty to handle adding new properties as well as editing existing ones
  const handleSaveProperty = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingProperty) {
      const exists = properties.some(p => p.id === editingProperty.id);
      if (exists) {
        setProperties(properties.map(p => p.id === editingProperty.id ? editingProperty : p));
      } else {
        setProperties([editingProperty, ...properties]);
      }
      setEditingProperty(null);
    }
  };

  const downloadPropertiesCSV = () => {
    const headers = ["REF", "Título", "Tipo", "Operación", "Precio", "Moneda", "Localidad", "Vistas", "Leads"];
    const rows = properties.map(p => [
      p.ref,
      p.title,
      p.type,
      p.operation,
      p.price,
      p.currency,
      p.location.locality,
      p.viewsCount,
      p.leadsCount
    ]);
    const csvContent = "data:text/csv;charset=utf-8," + headers.join(",") + "\n" + rows.map(e => e.join(",")).join("\n");
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `propiedades_bm_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const downloadLeadsCSV = () => {
    const headers = ["Fecha", "Nombre", "Email", "Teléfono", "Propiedad", "Fuente", "Estado"];
    const rows = leads.map(l => [
      new Date(l.createdAt).toLocaleDateString(),
      l.name,
      l.email,
      l.phone,
      l.propertyRef || "Consulta Gral",
      l.source,
      l.status
    ]);
    const csvContent = "data:text/csv;charset=utf-8," + headers.join(",") + "\n" + rows.map(e => e.join(",")).join("\n");
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `clientes_bm_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
