import React, { useState, useMemo } from 'react';
import { Property, PropertyType, OperationType, SyncStats, Lead, User, UserRole } from '../types';
import { MOCK_PROPERTIES, MOCK_LEADS, MOCK_USERS } from '../constants';
import { syncWithGvamax } from '../services/syncService';

type AdminView = 'overview' | 'properties' | 'leads' | 'users' | 'sync' | 'settings';

interface AdminDashboardProps {
  currentUser: User;
  onLogout: () => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ currentUser, onLogout }) => {
  const [activeView, setActiveView] = useState<AdminView>('overview');
  const [properties, setProperties] = useState<Property[]>(MOCK_PROPERTIES);
  const [leads, setLeads] = useState<Lead[]>(MOCK_LEADS);
  const [users, setUsers] = useState<User[]>(MOCK_USERS);
  const [isSyncing, setIsSyncing] = useState(false);
  const [syncHistory, setSyncHistory] = useState<SyncStats[]>([]);
  const [editingProperty, setEditingProperty] = useState<Property | null>(null);
  const [selectedLead, setSelectedLead] = useState<Lead | null>(null);
  const [editingUser, setEditingUser] = useState<User | null>(null);

  const stats = useMemo(() => {
    return {
      total: properties.length,
      active: properties.filter(p => p.status === 'active').length,
      leads: leads.length,
      newLeads: leads.filter(l => l.status === 'new').length,
      views: properties.reduce((acc, p) => acc + p.viewsCount, 0),
    };
  }, [properties, leads]);

  const handleSync = async () => {
    setIsSyncing(true);
    try {
      const result = await syncWithGvamax();
      setSyncHistory([result, ...syncHistory]);
    } catch (e) {
      console.error("Error en la sincronización.");
    } finally {
      setIsSyncing(false);
    }
  };

  const updateLeadStatus = (leadId: string, newStatus: Lead['status']) => {
    setLeads(leads.map(l => l.id === leadId ? { ...l, status: newStatus } : l));
  };

  const handleDuplicate = (id: string) => {
    const property = properties.find(p => p.id === id);
    if (property) {
      const duplicated = {
        ...property,
        id: Math.random().toString(36).substring(7),
        ref: `${property.ref}-CLONE`,
        title: `${property.title} (Copia)`,
        createdAt: new Date().toISOString(),
        viewsCount: 0,
        leadsCount: 0
      };
      setProperties([duplicated, ...properties]);
    }
  };

  const handleArchive = (id: string) => {
    if (confirm("¿Seguro que desea archivar esta propiedad?")) {
      setProperties(properties.map(p => p.id === id ? { ...p, status: 'archived' as const } : p));
    }
  };

  const handleManualUpload = () => {
    const newProperty: Property = {
      id: Math.random().toString(36).substring(7),
      externalId: '',
      ref: `REF-${Math.floor(Math.random() * 10000)}`,
      title: '',
      description: '',
      type: PropertyType.APARTMENT,
      operation: OperationType.SALE,
      price: 0,
      currency: 'USD',
      neighborhood: '',
      location: { address: '', city: 'San Juan', province: 'San Juan', department: '', locality: '' },
      features: { rooms: 0, bedrooms: 0, bathrooms: 0, m2Total: 0, m2Covered: 0, amenities: [] },
      images: [],
      status: 'active',
      viewsCount: 0,
      leadsCount: 0,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      lastSyncAt: new Date().toISOString()
    };
    setEditingProperty(newProperty);
  };

  const handleSaveProperty = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingProperty) {
      const exists = properties.some(p => p.id === editingProperty.id);
      if (exists) {
        setProperties(properties.map(p => p.id === editingProperty.id ? editingProperty : p));
      } else {
        setProperties([editingProperty, ...properties]);
      }
      setEditingProperty(null);
    }
  };

  const menuItems = [
    { id: 'overview', label: 'Dashboard', icon: <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2H6a2 2 0 01-2-2V6zM14 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2h-2a2 2 0 01-2-2V6zM4 16a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2H6a2 2 0 01-2-2v-2zM14 16a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2h-2a2 2 0 01-2-2v-2z" /></svg> },
    { id: 'properties', label: 'Propiedades', icon: <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6" /></svg> },
    { id: 'leads', label: 'Clientes', icon: <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z" /></svg> },
    { id: 'users', label: 'Usuarios', icon: <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" /></svg> },
    { id: 'sync', label: 'Historial Sync', icon: <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg> },
  ];

  return (
    <div className="flex min-h-[calc(100vh-6rem)] bg-slate-50/30 animate-in fade-in duration-500">
      <aside className="w-72 bg-white border-r border-slate-100 p-8 space-y-4 hidden lg:block sticky top-24 h-[calc(100vh-6rem)]">
        <div className="mb-10 flex items-center gap-4 px-4">
          <img src={currentUser.avatar} className="w-10 h-10 rounded-xl shadow-sm border border-slate-100" alt="" />
          <div className="min-w-0">
            <p className="font-black text-slate-900 text-sm truncate">{currentUser.name}</p>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{currentUser.role}</p>
          </div>
        </div>

        <div className="space-y-1">
          {menuItems.map((item) => (
            <button 
              key={item.id}
              onClick={() => setActiveView(item.id as AdminView)}
              className={`w-full flex items-center gap-4 px-6 py-4 rounded-[1.5rem] font-bold transition-all duration-300 ${activeView === item.id ? 'bg-slate-900 text-white shadow-xl shadow-slate-200' : 'text-slate-500 hover:bg-slate-50'}`}
            >
              {item.icon}
              <span className="text-sm">{item.label}</span>
            </button>
          ))}
        </div>

        <div className="pt-8 border-t border-slate-100 space-y-3">
          <button 
            onClick={handleSync}
            disabled={isSyncing}
            className="w-full flex items-center justify-center gap-3 bg-red-600 text-white px-6 py-4 rounded-[1.5rem] font-black text-xs uppercase tracking-widest hover:bg-red-700 transition-all shadow-xl shadow-red-100 disabled:opacity-50"
          >
            {isSyncing ? 'Sincronizando...' : 'Sync Gvamax'}
          </button>
          <button 
            onClick={onLogout}
            className="w-full flex items-center justify-center gap-3 bg-slate-100 text-slate-600 px-6 py-4 rounded-[1.5rem] font-black text-xs uppercase tracking-widest hover:bg-red-50 hover:text-red-600 transition-all"
          >
            Cerrar Sesión
          </button>
        </div>
      </aside>

      <main className="flex-1 p-8 md:p-12 overflow-y-auto">
        {activeView === 'overview' && (
          <div className="space-y-10 animate-in fade-in slide-in-from-top-4 duration-500">
            <div className="flex justify-between items-end">
              <div>
                <h2 className="text-4xl font-black text-slate-900 tracking-tight">Panel de Control</h2>
                <p className="text-slate-400 font-medium">Estadísticas de rendimiento en tiempo real.</p>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
              {[
                { label: 'Propiedades', value: stats.total, icon: '🏠' },
                { label: 'Activas', value: stats.active, icon: '✅' },
                { label: 'Nuevos Leads', value: stats.newLeads, icon: '📩' },
                { label: 'Visitas Totales', value: stats.views.toLocaleString(), icon: '👁️' },
              ].map((card, i) => (
                <div key={i} className="bg-white p-8 rounded-[2.5rem] border border-slate-50 shadow-sm">
                  <span className="text-2xl mb-4 block">{card.icon}</span>
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{card.label}</p>
                  <p className="text-3xl font-black text-slate-900">{card.value}</p>
                </div>
              ))}
            </div>

            <div className="bg-white p-10 rounded-[3rem] shadow-sm border border-slate-50">
              <h3 className="text-xl font-black text-slate-900 mb-6">Actividad Reciente</h3>
              <p className="text-slate-400 font-medium italic">Gráfico de rendimiento próximamente disponible mediante sincronización CRM avanzada.</p>
            </div>
          </div>
        )}

        {activeView === 'properties' && (
          <div className="space-y-8 animate-in fade-in slide-in-from-top-4 duration-500">
            <div className="flex justify-between items-center">
              <div>
                <h2 className="text-4xl font-black text-slate-900 tracking-tight">Propiedades</h2>
                <p className="text-slate-400 font-medium">Gestión de stock inmobiliario.</p>
              </div>
              <button onClick={handleManualUpload} className="bg-slate-900 text-white px-8 py-4 rounded-2xl font-black uppercase text-xs tracking-widest hover:bg-red-600 transition-all shadow-xl">
                Nueva Propiedad
              </button>
            </div>

            <div className="bg-white rounded-[2.5rem] shadow-sm overflow-hidden border border-slate-50">
              <table className="w-full text-left">
                <thead className="bg-slate-50 text-[10px] font-black uppercase text-slate-400 tracking-widest">
                  <tr>
                    <th className="px-8 py-6">Inmueble</th>
                    <th className="px-8 py-6">Precio</th>
                    <th className="px-8 py-6">Métricas</th>
                    <th className="px-8 py-6 text-right">Acciones</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {properties.map(p => (
                    <tr key={p.id} className="hover:bg-slate-50/50 transition-colors">
                      <td className="px-8 py-6">
                        <div className="flex items-center gap-4">
                          <img src={p.images[0]?.url} className="w-16 h-12 rounded-xl object-cover" alt="" />
                          <div>
                            <p className="font-black text-slate-900">{p.title}</p>
                            <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">{p.ref}</p>
                          </div>
                        </div>
                      </td>
                      <td className="px-8 py-6">
                        <p className="font-black text-blue-600">{p.currency} {p.price.toLocaleString()}</p>
                        <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{p.operation}</p>
                      </td>
                      <td className="px-8 py-6 text-xs font-bold text-slate-500">
                        {p.viewsCount} Vistas / {p.leadsCount} Leads
                      </td>
                      <td className="px-8 py-6 text-right space-x-2">
                        <button onClick={() => setEditingProperty(p)} className="p-2 text-slate-400 hover:text-blue-600 transition-colors">✏️</button>
                        <button onClick={() => handleDuplicate(p.id)} className="p-2 text-slate-400 hover:text-slate-900 transition-colors">📑</button>
                        <button onClick={() => handleArchive(p.id)} className="p-2 text-slate-400 hover:text-red-600 transition-colors">🗑️</button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {/* Editing Property Modal */}
        {editingProperty && (
          <div className="fixed inset-0 z-[200] bg-slate-900/60 backdrop-blur-md flex items-center justify-center p-6">
            <div className="bg-white w-full max-w-4xl rounded-[3rem] shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
              <header className="px-10 py-8 border-b border-slate-50 flex justify-between items-center">
                <h3 className="text-2xl font-black text-slate-900">Editar Propiedad</h3>
                <button onClick={() => setEditingProperty(null)} className="text-slate-400 hover:text-slate-900">Cerrar</button>
              </header>
              <form onSubmit={handleSaveProperty} className="p-10 overflow-y-auto space-y-6">
                <div className="grid grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-slate-400">Título</label>
                    <input className="w-full px-6 py-4 bg-slate-50 rounded-xl outline-none font-bold" value={editingProperty.title} onChange={e => setEditingProperty({...editingProperty, title: e.target.value})} />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-slate-400">Precio</label>
                    <input type="number" className="w-full px-6 py-4 bg-slate-50 rounded-xl outline-none font-bold" value={editingProperty.price} onChange={e => setEditingProperty({...editingProperty, price: parseInt(e.target.value)})} />
                  </div>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-slate-400">Descripción</label>
                  <textarea className="w-full px-6 py-4 bg-slate-50 rounded-xl outline-none font-medium h-32" value={editingProperty.description} onChange={e => setEditingProperty({...editingProperty, description: e.target.value})} />
                </div>
                <button type="submit" className="bg-slate-900 text-white px-10 py-4 rounded-2xl font-black uppercase text-xs tracking-widest w-full">Guardar Cambios</button>
              </form>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default AdminDashboard;
